using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

Ptr CreateWireBody(std::vector>& edgeMap)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr center = Point3D::create(10.0, 0.0, 5.0);
    Ptr normal = Vector3D::create(0.0, 0.0, 1.0);
    Ptr circle1 = Circle3D::createByCenter(center, normal, 3.0);
    Ptr circle2 = Circle3D::createByCenter(center, normal, 2.0);

    std::vector> curves;
    curves.push_back(circle1);
    curves.push_back(circle2);

    // Create wire from curves
    Ptr wireBody = tempBRepMgr->createWireFromCurves(curves, edgeMap);

    return wireBody;
}

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    // Create a new document
    Ptr docs = app->documents();
    if (!docs)
        return false;

    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Set the design is a direct modelling design
    design->designType(adsk::fusion::DirectDesignType);

    // Get the root component of active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a sub component under root component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;

    Ptr transform = Matrix3D::create();
    if (!transform)
        return false;

    Ptr subOcc = occs->addNewComponent(transform);
    if (!subOcc)
        return false;

    Ptr subComp = subOcc->component();
    if (!subComp)
        return false;

    // Create temproray wire body
    std::vector> edgeMap;
    Ptr wireBody = CreateWireBody(edgeMap);
    if (!wireBody)
        return false;

    // Add wireBody to sub - component
    Ptr bodies = subComp->bRepBodies();
    if (!bodies)
        return false;
    bodies->add(wireBody);

    // Get the brep wire body
    Ptr brepWireBody = bodies->item(0);
    if (!brepWireBody)
        return false;

    // Get brep wires
    Ptr brepWires = brepWireBody->wires();
    if (!brepWires)
        return false;

    // Get brep wires count
    size_t count = brepWires->count();

    // Get brep wire
    Ptr brepWire = brepWires->item(0);
    if (!brepWire)
        return false;

    // Get brep edges from brepWire
    Ptr brepEdges = brepWire->edges();
    if (!brepEdges)
        return false;

    // Get vertices from brepWire
    Ptr vertices = brepWire->vertices();
    if (!vertices)
        return false;

    // Get brep coEdges from brepWire
    Ptr coEdges = brepWire->coEdges();
    // ON_ERROR_RETURN(coEdges);
    // if (!coEdges)
    //	return false;

    // Get the brep wire is planar or not
    bool isPlanar = brepWire->isPlanar();

    // Get wire's parent brep body
    Ptr parent = brepWire->parent();
    if (!parent)
        return false;

    // offse the planar brep wire

    Ptr planeNormal = Vector3D::create(0.0, 0.0, 1.0);
    Ptr offsetBody = brepWire->offsetPlanarWire(planeNormal, 3.0, OffsetCornerTypes::LinearOffsetCornerType);
    if (!offsetBody)
        return false;

    // Create brep wire proxy
    Ptr wireProxy = brepWire->createForAssemblyContext(subOcc);
    if (!wireProxy)
        return false;

    // Get native brep wire
    Ptr nativeBrepWire = wireProxy->nativeObject();
    if (!nativeBrepWire)
        return false;

    // Get the assembly occurrence
    Ptr occurence = wireProxy->assemblyContext();
    if (!occurence)
        return false;

    return true;
}
